function KeyTracker() {
  const [key, setKey] = useState('');

  useEffect(() => {
    function handleKeyDown(event) {
      setKey(event.key);
    }

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
    //            same function reference ↑ — required for removal to work
  }, []); // no dependencies: the handler never needs to change

  return <p>Last key pressed: {key}</p>;
}

function StepCounter({ step }) {
  const [count, setCount] = useState(0);

  useEffect(() => {
    function handleClick() {
      setCount(c => c + step); // closes over 'step'
    }

    window.addEventListener('click', handleClick);
    return () => window.removeEventListener('click', handleClick);
  }, [step]); // re-register when step changes

  return <p>Count: {count}</p>;
}

import { fromEvent } from 'rxjs';
import { debounceTime, map } from 'rxjs/operators';

function SearchBox() {
  const [query, setQuery] = useState('');
  const inputRef = useRef(null);

  useEffect(() => {
    const input = inputRef.current;
    const subscription = fromEvent(input, 'input').pipe(
      debounceTime(300),
      map(e => e.target.value),
    ).subscribe(value => setQuery(value));

    return () => subscription.unsubscribe(); // cleanup
  }, []); // effect runs once; RxJS stream handles subsequent events

  return <input ref={inputRef} placeholder="Search..." />;
}

function LiveFeed({ roomId }) {
  const [messages, setMessages] = useState([]);

  useEffect(() => {
    const socket = new WebSocket(`wss://example.com/rooms/${roomId}`);

    socket.onmessage = (event) => {
      const msg = JSON.parse(event.data);
      setMessages(prev => [...prev, msg]);
    };

    socket.onerror = (err) => {
      console.error('WebSocket error', err);
    };

    return () => socket.close(); // disconnect on unmount or roomId change
  }, [roomId]); // reconnect whenever roomId changes

  return <ul>{messages.map((m, i) => <li key={i}>{m.text}</li>)}</ul>;
}

function useIsMobile(breakpoint = '(max-width: 768px)') {
  const [isMobile, setIsMobile] = useState(
    () => window.matchMedia(breakpoint).matches
  );

  useEffect(() => {
    const mql = window.matchMedia(breakpoint);

    function handleChange(e) {
      setIsMobile(e.matches);
    }

    mql.addEventListener('change', handleChange);
    return () => mql.removeEventListener('change', handleChange);
  }, [breakpoint]);

  return isMobile;
}

function useElementSize(ref) {
  const [size, setSize] = useState({ width: 0, height: 0 });

  useEffect(() => {
    if (!ref.current) return;

    const observer = new ResizeObserver(([entry]) => {
      const { width, height } = entry.contentRect;
      setSize({ width, height });
    });

    observer.observe(ref.current);
    return () => observer.disconnect(); // cleanup
  }, [ref]); // ref is stable (useRef), so this runs once

  return size;
}

// ✗ Missing cleanup — memory leak
useEffect(() => {
  window.addEventListener('scroll', updateScrollPos);
  // no return — listener accumulates each time the effect runs
}, []);

// After 10 mounts/unmounts (e.g. from navigation):
// 10 scroll listeners are active, all calling setState on
// components that may no longer exist.

// ✓ Correct
useEffect(() => {
  window.addEventListener('scroll', updateScrollPos);
  return () => window.removeEventListener('scroll', updateScrollPos);
}, []);

// Correct cleanup — Strict Mode is fine:
// mount  → addEventListener('click', handler)
// unmount (Strict Mode) → removeEventListener('click', handler)
// remount → addEventListener('click', handler)
// Result: exactly one listener active

// Broken cleanup — Strict Mode reveals it:
// mount  → addEventListener('click', handler)
// unmount (Strict Mode) → nothing
// remount → addEventListener('click', handler)
// Result: two listeners both calling setState

function useEventListener(eventName, handler, target = window) {
  const handlerRef = useRef(handler);
  useEffect(() => { handlerRef.current = handler; });

  useEffect(() => {
    if (!target?.addEventListener) return;

    function listener(event) {
      handlerRef.current(event);
    }

    target.addEventListener(eventName, listener);
    return () => target.removeEventListener(eventName, listener);
  }, [eventName, target]);
}

// Usage:
function App() {
  const [key, setKey] = useState('');
  useEventListener('keydown', e => setKey(e.key));
  return <p>Key: {key}</p>;
}

function LazyImage({ src, alt }) {
  const [visible, setVisible] = useState(false);
  const ref = useRef(null);

  useEffect(() => {
    if (!ref.current) return;

    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setVisible(true);
          observer.disconnect(); // only need to trigger once
        }
      },
      { threshold: 0.1 }
    );

    observer.observe(ref.current);
    return () => observer.disconnect();
  }, []);

  return <div ref={ref}>{visible ? <img src={src} alt={alt} /> : null}</div>;
}

function LivePosition() {
  const [coords, setCoords] = useState(null);
  const [error, setError] = useState(null);

  useEffect(() => {
    if (!navigator.geolocation) {
      setError('Geolocation not supported');
      return;
    }

    const watchId = navigator.geolocation.watchPosition(
      pos => setCoords({ lat: pos.coords.latitude, lng: pos.coords.longitude }),
      err => setError(err.message),
      { enableHighAccuracy: true }
    );

    return () => navigator.geolocation.clearWatch(watchId);
  }, []);

  if (error) return <p>Error: {error}</p>;
  if (!coords) return <p>Locating...</p>;
  return <p>Lat: {coords.lat}, Lng: {coords.lng}</p>;
}

function ThemeSync() {
  const [theme, setTheme] = useState('light');

  useEffect(() => {
    const channel = new BroadcastChannel('theme');

    channel.onmessage = (event) => {
      setTheme(event.data.theme);
    };

    return () => channel.close(); // cleanup: close the port
  }, []);

  function broadcast(newTheme) {
    setTheme(newTheme);
    new BroadcastChannel('theme').postMessage({ theme: newTheme });
  }

  return (
    <>
      <p>Current theme: {theme}</p>
      <button onClick={() => broadcast('dark')}>Dark</button>
      <button onClick={() => broadcast('light')}>Light</button>
    </>
  );
}

import { store } from './store'; // hypothetical EventEmitter-based store

function UserStatus({ userId }) {
  const [status, setStatus] = useState(null);

  useEffect(() => {
    function onStatusChange(newStatus) {
      setStatus(newStatus);
    }

    store.on(`user:${userId}:status`, onStatusChange);
    return () => store.off(`user:${userId}:status`, onStatusChange);
  }, [userId]); // re-subscribe when userId changes

  return <span>{status ?? 'loading'}</span>;
}

function DragTracker() {
  const [dragging, setDragging] = useState(false);

  useEffect(() => {
    function onMouseDown() { setDragging(true); }
    function onMouseUp()   { setDragging(false); }

    window.addEventListener('mousedown', onMouseDown);
    window.addEventListener('mouseup',   onMouseUp);

    return () => {
      window.removeEventListener('mousedown', onMouseDown);
      window.removeEventListener('mouseup',   onMouseUp);
    };
  }, []);

  return <p>{dragging ? 'Dragging' : 'Idle'}</p>;
}

useEffect(() => {
  const options = { passive: true }; // tell browser: no preventDefault()

  function handleScroll() {
    setScrollY(window.scrollY);
  }

  window.addEventListener('scroll', handleScroll, options);
  return () => window.removeEventListener('scroll', handleScroll, options);
  //  options object ↑ must match the one used in addEventListener
}, []);
